import { Search } from "lucide-react";
import { useState } from "react";
import { verbs } from "../../data/data";
import Modal from "./Modal";
import VerbCard from "./VerbCard";

const VerbTable = () => {
  const [selected, setSelected] = useState(null);
  const [search, setSearch] = useState("");

  const filtered = verbs.filter((w) =>
    w.base.toLowerCase().includes(search.toLowerCase()),
  );

  return (
    <div className="w-full max-w-4xl mx-auto px-4 py-6 flex flex-col gap-5">
      {/* Header */}
      <div>
        <h1 className="text-xl font-semibold text-slate-100 mb-0.5">Verbs</h1>
        <p className="text-sm text-slate-400">
          <span className="text-emerald-400 font-medium">{verbs.length}</span>{" "}
          verbs available
        </p>
      </div>

      {/* Search */}
      <div className="relative">
        <Search
          size={14}
          className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500"
        />
        <input
          type="text"
          placeholder="Search verbs..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full bg-white/[0.04] border border-white/10 focus:border-sky-500/40 rounded-xl pl-9 pr-4 py-2.5 text-sm text-slate-200 placeholder:text-slate-500 outline-none transition-colors"
        />
      </div>

      {/* Verb cards */}
      <div className="flex flex-col gap-2.5">
        {filtered.map((v, i) => (
          <VerbCard key={i} verb={v} onSelect={setSelected} />
        ))}
      </div>

      {/* Empty state */}
      {filtered.length === 0 && (
        <div className="text-center py-12">
          <p className="text-sm text-slate-500">
            No verbs found for{" "}
            <span className="text-slate-300">&quot;{search}&quot;</span>
          </p>
        </div>
      )}

      <Modal data={selected} onClose={() => setSelected(null)} />
    </div>
  );
};

export default VerbTable;
